import{_ as e,o as i,c as t,a4 as d}from"./chunks/framework.4M7SpZrd.js";const h=JSON.parse('{"title":"Conformidade LGPD","description":"","frontmatter":{},"headers":[],"relativePath":"seguranca/lgpd.md","filePath":"seguranca/lgpd.md"}'),o={name:"seguranca/lgpd.md"};function r(l,a,s,n,c,m){return i(),t("div",null,[...a[0]||(a[0]=[d('<h1 id="conformidade-lgpd" tabindex="-1">Conformidade LGPD <a class="header-anchor" href="#conformidade-lgpd" aria-label="Permalink to &quot;Conformidade LGPD&quot;">​</a></h1><h2 id="visao-geral" tabindex="-1">Visao Geral <a class="header-anchor" href="#visao-geral" aria-label="Permalink to &quot;Visao Geral&quot;">​</a></h2><p>Kubex trata dados biometricos (face), dados pessoais (CPF, email), e dados de navegacao. A conformidade LGPD e integrada em todas as camadas do sistema.</p><h2 id="principio-minimizacao-de-dados" tabindex="-1">Principio: Minimizacao de Dados <a class="header-anchor" href="#principio-minimizacao-de-dados" aria-label="Permalink to &quot;Principio: Minimizacao de Dados&quot;">​</a></h2><h3 id="imagens-nunca-armazenadas" tabindex="-1">Imagens NUNCA armazenadas <a class="header-anchor" href="#imagens-nunca-armazenadas" aria-label="Permalink to &quot;Imagens NUNCA armazenadas&quot;">​</a></h3><ul><li>Pattern <code>del img_bytes</code> imediatamente apos processamento em todos os tasks</li><li>Apenas hashes (pHash, SHA1) e thumbnails (200px JPEG) sao mantidos</li><li>Evidence thumbnails expiram em 90 dias (migration 0053: evidence_expires_at)</li><li>Celery Beat: cleanup_expired_evidence executa diariamente</li></ul><h3 id="selfies-descartadas" tabindex="-1">Selfies descartadas <a class="header-anchor" href="#selfies-descartadas" aria-label="Permalink to &quot;Selfies descartadas&quot;">​</a></h3><ul><li>Video de liveness detection NUNCA sai do browser (MediaPipe JS local)</li><li>Apenas 1 frame JPEG 512x512 enviado ao backend</li><li>Frame descartado imediatamente apos gerar embedding</li><li>Embedding cifrado com AES-256-GCM (chave derivada de PBKDF2(user_id + SECRET_KEY))</li></ul><h2 id="criptografia" tabindex="-1">Criptografia <a class="header-anchor" href="#criptografia" aria-label="Permalink to &quot;Criptografia&quot;">​</a></h2><ul><li>CPF/CNPJ: AES-256-GCM (app/core/encryption.py)</li><li>Face embeddings: AES-256-GCM per-user key derivation</li><li>Chave mestra: ENCRYPTION_KEY env var</li></ul><h2 id="direito-ao-esquecimento-art-18" tabindex="-1">Direito ao Esquecimento (Art. 18) <a class="header-anchor" href="#direito-ao-esquecimento-art-18" aria-label="Permalink to &quot;Direito ao Esquecimento (Art. 18)&quot;">​</a></h2><ul><li>DELETE /users/me/delete — usuario pode deletar conta</li><li>CASCADE DELETE remove todos os dados: embeddings, alerts, searches, subscriptions</li><li>Audit logs preservados ANONIMIZADOS (FK ondelete=SET NULL — user_id vira NULL)</li></ul><h2 id="opt-out-de-dominio" tabindex="-1">Opt-out de Dominio <a class="header-anchor" href="#opt-out-de-dominio" aria-label="Permalink to &quot;Opt-out de Dominio&quot;">​</a></h2><ul><li>POST /api/v1/optout/ — endpoint publico, sem autenticacao</li><li>Webmaster solicita remocao do dominio da base (PIB)</li><li>Rate limit: 5/hora por IP</li><li>SSRF guard valida dominio</li><li>Fluxo: pending → admin review → aprovado (whitelist + Crawler desativado) / rejeitado</li><li id="">Admin endpoint: PATCH /admin/intelligence/optout/</li></ul><h2 id="audit-trail" tabindex="-1">Audit Trail <a class="header-anchor" href="#audit-trail" aria-label="Permalink to &quot;Audit Trail&quot;">​</a></h2><ul><li>Todas as acoes sensiveis registradas em audit_logs: <ul><li>Login, registro, logout</li><li>Setup/disable 2FA</li><li>Alteracao de senha</li><li>Exclusao de conta</li><li>Aprovacao/rejeicao de identidade</li><li>Revogacao de embedding</li></ul></li><li>User model: ondelete=SET NULL para audit_logs (preserva registros anonimizados)</li></ul><h2 id="consentimento" tabindex="-1">Consentimento <a class="header-anchor" href="#consentimento" aria-label="Permalink to &quot;Consentimento&quot;">​</a></h2><ul><li>Termos de uso e politica de privacidade obrigatorios no registro</li><li>Paginas: /termos, /privacidade</li></ul><h2 id="tabela-resumo-lgpd" tabindex="-1">Tabela Resumo LGPD <a class="header-anchor" href="#tabela-resumo-lgpd" aria-label="Permalink to &quot;Tabela Resumo LGPD&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Dado</th><th>Armazenamento</th><th>Retencao</th><th>Exclusao</th></tr></thead><tbody><tr><td>Imagem original</td><td>NUNCA armazenada</td><td>—</td><td>—</td></tr><tr><td>pHash/SHA1</td><td>PostgreSQL</td><td>Indefinido</td><td>CASCADE DELETE</td></tr><tr><td>Evidence thumbnail</td><td>PostgreSQL (base64)</td><td>90 dias</td><td>cleanup_expired_evidence</td></tr><tr><td>Face embedding</td><td>Milvus (encrypted)</td><td>Ate revogacao</td><td>CASCADE DELETE + Milvus delete</td></tr><tr><td>Selfie</td><td>Memoria apenas</td><td>Descartada imediatamente</td><td>del img_bytes</td></tr><tr><td>CPF/CNPJ</td><td>PostgreSQL (AES-256)</td><td>Ate exclusao de conta</td><td>CASCADE DELETE</td></tr><tr><td>Audit logs</td><td>PostgreSQL</td><td>Indefinido (anonimizado)</td><td>SET NULL (user_id)</td></tr></tbody></table>',20)])])}const p=e(o,[["render",r]]);export{h as __pageData,p as default};
